import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { PieChart, ResponsiveChartContainer, ChartsClipPath, LinePlot, ChartsXAxis } from '@mui/x-charts';
import response from './response.json';

interface MacroBreakdown {
  macro: string;
  percentage: number;
}

interface NutritionData {
  caloriesConsumed: {
    total: number;
    goal: number;
  };
  macrosBreakdown: MacroBreakdown[];
  mealCount: number;
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
}

export default function Widget() {
  const nutritionData = response.data as NutritionData;
  const metaData = response.meta as MetaData;
  const clipPathId = useId();

  const macrosData = nutritionData.macrosBreakdown.map((macro) => ({
    id: macro.macro,
    value: macro.percentage,
    label: `${macro.macro} (${macro.percentage}%)`,
  }));

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 420, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={700} sx={{ mb: 1, color: metaData.primaryColor }}>
              Nutrition Summary
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 0.5 }}>
              Calories Consumed
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#FF5722' }}>
              {nutritionData.caloriesConsumed.total}/{nutritionData.caloriesConsumed.goal}
            </Typography>
            <Typography variant="caption" color="text.secondary">
              Meals: {nutritionData.mealCount}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer series={[{ type: 'pie', data: macrosData, colorScheme: ['#FF5722', '#FFC107', '#FF9800'] }]}>
              <g clipPath={`url(#${clipPathId})`}>
                <PieChart />
              </g>
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
